<?php

declare(strict_types=1);

function sf_lco_transfer_configs(): array { $out=[];foreach(sf_lco_types() as$type=>$c)$out[$type]=['label'=>$c['label'],'table'=>$c['table'],'unique'=>[$c['slug']??'slug'],'defaults'=>[$c['status']=>$type==='character'?'inactive':'draft']];$out['plan']['defaults']=['status'=>'inactive'];return$out; }
function sf_lco_parse_transfer(?array $file,string $pasted): array { $max=2097152;$rows=[];if($file&&(int)($file['error']??UPLOAD_ERR_NO_FILE)!==UPLOAD_ERR_NO_FILE){if((int)$file['error']!==UPLOAD_ERR_OK||(int)$file['size']<1||(int)$file['size']>$max)throw new RuntimeException('Upload is invalid or exceeds 2 MB.');$ext=strtolower(pathinfo((string)$file['name'],PATHINFO_EXTENSION));if(!in_array($ext,['csv','json'],true))throw new RuntimeException('Only CSV and JSON are allowed.');$tmp=(string)$file['tmp_name'];if($ext==='json')$pasted=(string)file_get_contents($tmp);else{$h=fopen($tmp,'rb');$head=fgetcsv($h);if(!$head)throw new RuntimeException('CSV header is missing.');$head=array_map(fn($v)=>strtolower(trim(preg_replace('/[^a-z0-9_]+/i','_',ltrim((string)$v,"\xEF\xBB\xBF"))??'','_')),$head);while(($line=fgetcsv($h))!==false){if(count($line)!==count($head))throw new RuntimeException('CSV row width mismatch.');$rows[]=array_combine($head,$line)?:[];if(count($rows)>1000)throw new RuntimeException('Import exceeds 1,000 rows.');}fclose($h);return$rows;}}$pasted=trim($pasted);if($pasted==='')return[];if(strlen($pasted)>$max)throw new RuntimeException('JSON exceeds 2 MB.');$data=json_decode($pasted,true,32,JSON_THROW_ON_ERROR);$rows=array_values(isset($data['rows'])&&is_array($data['rows'])?$data['rows']:$data);if(count($rows)>1000)throw new RuntimeException('Import exceeds 1,000 rows.');return$rows; }
function sf_lco_transfer_preview(string $type,array $rows): array { $cfg=sf_lco_transfer_configs()[$type]??null;if(!$cfg||!sf_admin_table_exists($cfg['table']))return['ok'=>false,'errors'=>['Unsupported type or missing table.'],'rows'=>[]];$cols=sf_admin_table_columns($cfg['table']);$out=[];$errors=0;foreach($rows as$i=>$source){$clean=[];foreach((array)$source as$k=>$v){$key=strtolower(trim(preg_replace('/[^a-z0-9_]+/i','_', (string)$k)??'','_'));if($key!==''&&in_array($key,$cols,true)&&!in_array($key,['id','created_at','updated_at'],true))$clean[$key]=is_scalar($v)?trim((string)$v):sf_lco_json($v);}$payload=array_merge($cfg['defaults'],$clean);if(in_array('slug',$cols,true)&&empty($payload['slug'])){$title=$payload['title']??$payload['name']??$payload['character_name']??'';$payload['slug']=sf_admin_slugify((string)$title);}foreach(['price_cents','inventory_quantity','track_number','season_number','episode_number','duration_seconds','runtime_minutes'] as$n)if(isset($payload[$n]))$payload[$n]=max(0,(int)$payload[$n]);$rowErrors=[];$title=$payload['title']??$payload['name']??$payload['character_name']??'';if(trim((string)$title)==='')$rowErrors[]='Missing title/name.';if(in_array('slug',$cols,true)&&empty($payload['slug']))$rowErrors[]='Missing slug.';$errors+=count($rowErrors)>0?1:0;$out[]=['row_number'=>$i+1,'ok'=>!$rowErrors,'payload'=>$payload,'errors'=>$rowErrors];}return['ok'=>$errors===0&&$out,'errors'=>$errors,'rows'=>$out,'digest'=>hash('sha256',sf_lco_json($out))]; }
function sf_lco_transfer_commit(string $type,array $rows,string $confirmation=''): array { if(!hash_equals('IMPORT',strtoupper(trim($confirmation))))return['ok'=>false,'message'=>'Type IMPORT exactly.'];$preview=sf_lco_transfer_preview($type,$rows);if(!$preview['ok'])return['ok'=>false,'message'=>'Preview has errors.','preview'=>$preview];$cfg=sf_lco_transfer_configs()[$type];$table=sf_lco_identifier($cfg['table']);$batch=sf_lco_batch_start('catalog_import',$confirmation);$summary=['items'=>count($preview['rows']),'success'=>0,'failed'=>0];$pdo=sf_admin_db();try{$pdo->beginTransaction();foreach($preview['rows'] as$item){$p=$item['payload'];$where=[];$params=[];foreach($cfg['unique'] as$u)if(isset($p[$u])&&$p[$u]!==''){$where[]='`'.sf_lco_identifier($u).'`=?';$params[]=$p[$u];}$before=$where?sf_admin_fetch_one('SELECT * FROM `'.$table.'` WHERE '.implode(' AND ',$where).' LIMIT 1',$params):null;if($before){$ok=sf_lco_update_row($type,(int)$before['id'],$p);$id=(int)$before['id'];$after=$ok?sf_admin_fetch_one('SELECT * FROM `'.$table.'` WHERE id=?',[$id]):null;}else{$cols=array_keys($p);$sql='INSERT INTO `'.$table.'` (`'.implode('`,`',array_map('sf_lco_identifier',$cols)).'`) VALUES ('.implode(',',array_fill(0,count($cols),'?')).')';$ok=$pdo->prepare($sql)->execute(array_values($p));$id=(int)$pdo->lastInsertId();$after=$ok?sf_admin_fetch_one('SELECT * FROM `'.$table.'` WHERE id=?',[$id]):null;}sf_lco_batch_action($batch,$type,$id,'catalog_import',$before,$after,$ok?'success':'failed',$ok?'':'Import write failed.');$ok?$summary['success']++:$summary['failed']++;if(!$ok)throw new RuntimeException('Import write failed.');}$pdo->commit();sf_lco_batch_finish($batch,$summary,'completed');return['ok'=>true,'batch_id'=>$batch]+$summary;}catch(Throwable $e){if($pdo&&$pdo->inTransaction())$pdo->rollBack();$summary['failed']=max(1,$summary['failed']);sf_lco_batch_finish($batch,$summary,'failed');return['ok'=>false,'message'=>'Import rolled back: '.$e->getMessage(),'batch_id'=>$batch]+$summary;} }
function sf_lco_export_csv(string $type): string { $cfg=sf_lco_transfer_configs()[$type]??null;if(!$cfg)return'';$rows=sf_lco_rows($type,5000);if(!$rows)return'';$columns=[];foreach($rows as$row)foreach(array_keys($row) as$c)if(!in_array($c,['password_hash','token','secret'],true))$columns[$c]=true;$columns=array_keys($columns);$h=fopen('php://temp','w+');fputcsv($h,$columns);foreach($rows as$row){$line=[];foreach($columns as$c){$v=$row[$c]??'';$line[]=is_scalar($v)?$v:sf_lco_json($v);}fputcsv($h,$line);}rewind($h);$csv=(string)stream_get_contents($h);fclose($h);if(sf_admin_table_exists('catalog_export_runs'))sf_admin_execute('INSERT INTO catalog_export_runs (export_key,entity_type,export_format,row_count,content_sha256,created_by_user_id) VALUES (?,? ,"csv",?,?,?)',[sf_lco_key('export'),$type,count($rows),hash('sha256',$csv),sf_current_user_id()?:null]);return$csv; }
function sf_lco_event_claim(string $eventKey,string $eventType,array $metadata=[]): bool { if(!sf_admin_table_exists('catalog_operation_events')||!preg_match('/^[a-zA-Z0-9._:-]{8,64}$/',$eventKey))return false;try{return sf_admin_execute('INSERT INTO catalog_operation_events (event_key,event_type,event_status,metadata_json,created_by_user_id) VALUES (?,? ,"processing",?,?)',[$eventKey,$eventType,sf_lco_json($metadata),sf_current_user_id()?:null]);}catch(Throwable $e){return false;} }
function sf_lco_event_finish(string $eventKey,string $status,array $metadata=[]): void { if(sf_admin_table_exists('catalog_operation_events'))sf_admin_execute('UPDATE catalog_operation_events SET event_status=?,metadata_json=? WHERE event_key=?',[$status,sf_lco_json($metadata),$eventKey]); }
function sf_lco_run_series_due(): array { if(!sf_admin_table_exists('catalog_series'))return['ok'=>false,'checked'=>0,'changed'=>0];$rows=sf_admin_fetch_all("SELECT * FROM catalog_series WHERE status='scheduled' AND release_at IS NOT NULL AND release_at<=UTC_TIMESTAMP() ORDER BY release_at ASC LIMIT 100");$changed=0;foreach($rows as$row)if(sf_lco_update_row('series',(int)$row['id'],['status'=>'published']))$changed++;return['ok'=>true,'checked'=>count($rows),'changed'=>$changed]; }
function sf_lco_run_due(string $eventKey): array { if(!sf_lco_event_claim($eventKey,'catalog_due_runner'))return['ok'=>false,'error'=>'duplicate_or_invalid_event'];$publish=sf_publish_run_due();$series=sf_lco_run_series_due();$scan=sf_lco_scan(true,(string)(getenv('SF_RELEASE_COMMIT_SHA')?:''));$result=['publish'=>$publish,'series'=>$series,'readiness_score'=>$scan['overall_score'],'snapshot_id'=>$scan['snapshot_id']??0];$ok=!empty($publish['ok'])&&!empty($series['ok']);sf_lco_event_finish($eventKey,$ok?'completed':'failed',$result);return['ok'=>$ok]+$result; }
